index 932d827..04dfd3f 100644
--- a/src/Carbon/CarbonPeriod.php
+++ b/src/Carbon/CarbonPeriod.php
@@ -2503,6 +2503,10 @@ class CarbonPeriod extends DatePeriodBase implements Countable, JsonSerializable
     /**
      * Keep incrementing the current date until a valid date is found or the iteration is ended.
      *
+     * When iterating with a time-based interval across a DST boundary, the UTC offset in the
+     * target timezone may change. We compensate for that offset change so that wall-clock steps
+     * are preserved (e.g. each hourly step produces a different wall-clock hour).
+     *
      * @throws RuntimeException
      */
     protected function incrementCurrentDateUntilValid(): void
@@ -2510,7 +2514,19 @@ class CarbonPeriod extends DatePeriodBase implements Countable, JsonSerializable
         $attempts = 0;

         do {
-            $this->carbonCurrent = $this->carbonCurrent->add($this->dateInterval);
+            if ($this->timezone) {
+                $offsetBefore = $this->carbonCurrent->setTimezone($this->timezone)->getOffset();
+                $this->carbonCurrent = $this->carbonCurrent->add($this->dateInterval);
+                $offsetAfter = $this->carbonCurrent->setTimezone($this->timezone)->getOffset();
+                $offsetDiff = $offsetAfter - $offsetBefore;
+
+                if ($offsetDiff !== 0) {
+                    // DST transition detected: adjust by the offset difference to preserve wall-clock step size.
+                    $this->carbonCurrent = $this->carbonCurrent->addSeconds(-$offsetDiff);
+                }
+            } else {
+                $this->carbonCurrent = $this->carbonCurrent->add($this->dateInterval);
+            }

             $this->validationResult = null;
